SELECT COUNT(*)
  FROM TB_REVIEW
 WHERE REVIEW_TYPE = 'HOSPITAL'
   AND RESV_ID = #{resvId}
   AND MEMBER_NO = #{memberNo}

mapper.update:
UPDATE TB_HOSPITAL H
   SET AVG_RATING = (
         SELECT ROUND(AVG(R.RATING), 1)
           FROM TB_REVIEW R
          WHERE R.REVIEW_TYPE = 'HOSPITAL'
            AND R.TARGET_ID = #{hospitalId}
       ),
       REVIEW_CNT = (
         SELECT COUNT(*)
           FROM TB_REVIEW R
          WHERE R.REVIEW_TYPE = 'HOSPITAL'
            AND R.TARGET_ID = #{hospitalId}
       )
 WHERE H.HOSPITAL_ID = #{hospitalId}
